15	//! Logging infrastructure — severity-named macros with auto file/line capture.
16	//!
17	//! All application logging goes through `apcrl_*_now!`, `apcrl_*_if!`, and
18	//! comparison variants. No naked `println!`/`eprintln!` elsewhere in the codebase.
19	//!
20	//! Output is line-oriented to stdout. Format:
21	//!   `[LEVEL] [file:line] message`
22	//!
23	//! An optional file-tee sink can be installed via `apcrl_tee_init` once at
24	//! application startup. When present, every emission is appended to the tee
25	//! file in the exact format that goes to stdout — one format, two sinks. Tee
26	//! write failures are swallowed to avoid recursive-logging hazards; stdout
27	//! remains authoritative.
28	//!
29	//! Suffix families:
30	//!   `_now`  — unconditional emission
31	//!   `_if`   — boolean conditional, returns the bool
32	//!   `_eq`, `_ne`, `_lt`, `_gt`, `_le`, `_ge` — comparison conditional,
33	//!            stringifies arguments, returns the bool
34	
35	use std::fs::{File, OpenOptions};
36	use std::io::Write;
37	use std::path::Path;
38	use std::sync::{Mutex, OnceLock};
39	
40	pub const APCRL_LEVEL_TRACE: &str = "[TRACE]";
41	pub const APCRL_LEVEL_INFO:  &str = "[INFO]";
42	pub const APCRL_LEVEL_ERROR: &str = "[ERROR]";
43	pub const APCRL_LEVEL_FATAL: &str = "[FATAL]";
44	
45	static ZAPCRL_TEE: OnceLock<Mutex<File>> = OnceLock::new();
46	
47	/// Install a file-tee sink. Every subsequent `apcrl_*` emission is appended
48	/// to `path` in the exact format that goes to stdout. The file is opened in
49	/// append-create mode. Call once from application startup; subsequent calls
50	/// return `Err` without disturbing the active sink.
51	pub fn apcrl_tee_init(path: &Path) -> Result<(), String> {
52	    let file = OpenOptions::new()
53	        .create(true)
54	        .append(true)
55	        .open(path)
56	        .map_err(|e| format!("open tee file {}: {}", path.display(), e))?;
57	    ZAPCRL_TEE.set(Mutex::new(file))
58	        .map_err(|_| "tee already initialized".to_string())?;
59	    Ok(())
60	}
61	
62	fn zapcrl_tee_write(line: &str) {
63	    if let Some(mtx) = ZAPCRL_TEE.get() {
64	        if let Ok(mut f) = mtx.lock() {
65	            let _ = writeln!(f, "{}", line);
66	            let _ = f.flush();
67	        }
68	    }
69	}
70	
71	#[doc(hidden)]
72	pub fn zapcrl_emit(level: &str, file: &str, line: u32, msg: &str) {
73	    let formatted = format!("{} [{}:{}] {}", level, file, line, msg);
74	    println!("{}", formatted);
75	    zapcrl_tee_write(&formatted);
76	}
77	
78	#[doc(hidden)]
79	pub fn zapcrl_emit_fatal(file: &str, line: u32, msg: &str) -> ! {
80	    let formatted = format!("{} [{}:{}] {}", APCRL_LEVEL_FATAL, file, line, msg);
81	    println!("{}", formatted);
82	    zapcrl_tee_write(&formatted);
83	    std::process::exit(1);
84	}
