32	/// files in `dir`. Returns the N used. N seeds at
33	/// `APCRH_HARVEST_SEED_INDEX` when `dir` is empty, otherwise
34	/// `max_leading_digit_run + 1` across any filenames that begin with digits
35	/// (bare `{N}.{ext}`, `{N}-in.{ext}`, `{N}-out.{ext}` all count). The
36	/// directory is created lazily. Text is required; HTML is opportunistic —
37	/// absence of HTML on the clipboard is not an error.
38	pub fn apcrh_capture_all_flavors(dir: &Path) -> Result<u32, String> {
39	    fs::create_dir_all(dir)
40	        .map_err(|e| format!("create harvest dir {}: {}", dir.display(), e))?;
41	
42	    let index = zapcrh_scan_next_index(dir)?;
43	
44	    let mut clipboard = arboard::Clipboard::new()
45	        .map_err(|e| format!("clipboard open: {}", e))?;
