47	    let text = clipboard.get_text()
48	        .map_err(|e| format!("clipboard get_text: {}", e))?;
49	    zapcrh_write_text(dir, index, &text)?;
50	
51	    // HTML is opportunistic — absence on the clipboard is expected for some
52	    // sources, not an error. Capture when present, skip otherwise.
53	    if let Ok(html) = clipboard.get().html() {
54	        zapcrh_write_html(dir, index, &html)?;
55	    }
