62	/// name does not start with a digit (e.g. `apcap.log`, `README`) are
63	/// ignored, as are subdirectories. Gaps are not filled — the scan advances
64	/// past the current maximum. The leading-digit parse makes mixed naming
65	/// styles — bare `{N}.{ext}`, `{N}-in.{ext}`, `{N}-out.{ext}` — all count
66	/// toward the same index space.
67	pub(crate) fn zapcrh_scan_next_index(dir: &Path) -> Result<u32, String> {
68	    let entries = fs::read_dir(dir)
69	        .map_err(|e| format!("read harvest dir {}: {}", dir.display(), e))?;
70	
71	    let mut max: Option<u32> = None;
72	    for entry in entries {
73	        let entry = entry
74	            .map_err(|e| format!("read harvest entry: {}", e))?;
75	        if !entry.file_type().map(|t| t.is_file()).unwrap_or(false) {
76	            continue;
77	        }
78	        let path = entry.path();
79	        let name = match path.file_name().and_then(|s| s.to_str()) {
80	            Some(s) => s,
81	            None    => continue,
82	        };
