12	// See the License for the specific language governing permissions and
13	// limitations under the License.
14	
15	#![deny(warnings)]
16	#![allow(non_camel_case_types)]
17	#![allow(private_interfaces)]
18	#![cfg_attr(not(debug_assertions), windows_subsystem = "windows")]
19	
20	// RCG output discipline: all emission via apcrl_*! — no direct println!/eprintln!
21	
22	use std::sync::{Mutex, OnceLock};
23	use apcd::apcrm_match::{apcrm_Finding, apcrm_Severity, apcrm_PhiCategory};
24	
25	// ---------------------------------------------------------------------------
26	// Statics — dictionary cache, clipboard tracking, toggle state
27	// ---------------------------------------------------------------------------
28	
29	static ZAPCAP_DICTS: OnceLock<apcd::apcrd_dictionaries::apcrd_Dictionaries> = OnceLock::new();
30	static ZAPCAP_LAST_CLIPBOARD: Mutex<Option<String>> = Mutex::new(None);
31	static ZAPCAP_LAST_CLINICAL: Mutex<Option<zapcap_ClinicalCache>> = Mutex::new(None);
32	static ZAPCAP_TOGGLE_STATES: Mutex<Vec<String>> = Mutex::new(Vec::new());
33	
34	struct zapcap_ClinicalCache {
35	    findings:   Vec<apcrm_Finding>,
36	    plain_text: String,
37	}
38	
39	// ---------------------------------------------------------------------------
40	// Focus handler — read clipboard, run detection, push rendered HTML
41	// ---------------------------------------------------------------------------
42	
43	fn zapcap_handle_focus(window: &tauri::WebviewWindow) -> Result<(), String> {
44	    let mut clipboard = arboard::Clipboard::new()
45	        .map_err(|e| format!("clipboard error: {}", e))?;
46	
47	    let content = clipboard.get_text()
48	        .map_err(|e| format!("clipboard error: {}", e))?;
49	
50	    apcd::apcrl_info_now!("focus: {} bytes", content.len());
51	
52	    // Change detection — same content as last invocation → preserve UI state
53	    {
54	        let last = ZAPCAP_LAST_CLIPBOARD.lock()
55	            .map_err(|e| format!("lock error: {}", e))?;
56	        if last.as_deref() == Some(content.as_str()) {
57	            apcd::apcrl_info_now!("focus: unchanged");
58	            return Ok(());
59	        }
60	    }
61	
62	    let dicts = ZAPCAP_DICTS.get_or_init(apcd::apcrd_dictionaries::apcrd_Dictionaries::apcrd_load);
63	
64	    match apcd::apcre_engine::apcre_analyze(&content, dicts) {
65	        apcd::apcre_engine::apcre_Result::Clinical { findings, plain_text } => {
66	            apcd::apcrl_info_now!("clinical: {} findings", findings.len());
67	            // Harvest every arboard-accessible flavor before the clipboard
68	            // zero-out, then pair the input with a default-elide anonymized
69	            // output. Output-at-focus uses an empty toggle-states slice —
70	            // apcre_anonymize defaults to elide for missing entries —
71	            // producing what Ann would get if she copied without touching
72	            // any toggles. Per-toggle refresh of the output file is a
73	            // deferred UX pace; this pairing is about legible debug signal.
74	            match apcd::apcrj_journal::apcrj_journal_path() {
75	                Some(journal_dir) => {
76	                    match apcd::apcrh_harvest::apcrh_capture_all_flavors(&journal_dir) {
77	                        Ok(n) => {
78	                            apcd::apcrl_info_now!("harvest captured as {}", n);
79	                            let anonymized = apcd::apcre_engine::apcre_anonymize(
80	                                &plain_text, &findings, &[],
81	                            );
82	                            let out_path = journal_dir.join(format!("{}-out.txt", n));
83	                            match std::fs::write(&out_path, &anonymized) {
84	                                Ok(()) => apcd::apcrl_info_now!(
85	                                    "anonymized written as {}-out.txt", n
86	                                ),
87	                                Err(e) => apcd::apcrl_error_now!(
88	                                    "anonymized write failed: {}", e
89	                                ),
90	                            }
91	                        }
92	                        Err(e) => apcd::apcrl_error_now!("harvest capture failed: {}", e),
93	                    }
94	                }
95	                None => {
96	                    apcd::apcrl_error_now!("harvest skipped: HOME not set");
97	                }
98	            }
99	
100	            // Clear system clipboard after consuming clinical content
101	            let _ = clipboard.set_text(String::new());
102	
103	            {
104	                let mut last = ZAPCAP_LAST_CLIPBOARD.lock()
105	                    .map_err(|e| format!("lock error: {}", e))?;
106	                *last = Some(String::new());
107	            }
108	
109	            {
110	                let mut toggle_states = ZAPCAP_TOGGLE_STATES.lock()
111	                    .map_err(|e| format!("lock error: {}", e))?;
112	                *toggle_states = vec!["elide".to_string(); findings.len()];
113	            }
114	
115	            {
116	                let mut cache = ZAPCAP_LAST_CLINICAL.lock()
117	                    .map_err(|e| format!("lock error: {}", e))?;
118	                *cache = Some(zapcap_ClinicalCache { findings, plain_text });
119	            }
120	
121	            zapcap_push_triage(window)
122	        }
123	        apcd::apcre_engine::apcre_Result::NonClinical { content_length, content_type, preview } => {
124	            apcd::apcrl_info_now!("non-clinical: {} ({} bytes)", content_type, content_length);
125	            {
126	                let mut last = ZAPCAP_LAST_CLIPBOARD.lock()
127	                    .map_err(|e| format!("lock error: {}", e))?;
128	                *last = Some(content);
129	            }
130	
131	            {
132	                let mut cache = ZAPCAP_LAST_CLINICAL.lock()
133	                    .map_err(|e| format!("lock error: {}", e))?;
134	                *cache = None;
135	            }
136	
137	            {
138	                let mut toggle_states = ZAPCAP_TOGGLE_STATES.lock()
139	                    .map_err(|e| format!("lock error: {}", e))?;
140	                *toggle_states = Vec::new();
141	            }
142	
143	            let diagnostic = format!(
144	                "Not clinical ({} bytes, {}): {}",
145	                content_length, content_type, preview
146	            );
147	            zapcap_push_instruction(window, &diagnostic)
148	        }
149	    }
150	}
151	
152	// ---------------------------------------------------------------------------
153	// Tauri commands — toggle finding, copy anonymized
154	// ---------------------------------------------------------------------------
155	
156	#[tauri::command]
157	fn toggle_finding(index: usize, window: tauri::WebviewWindow) -> Result<(), String> {
158	    {
159	        let mut states = ZAPCAP_TOGGLE_STATES.lock()
160	            .map_err(|e| format!("lock error: {}", e))?;
161	        if index < states.len() {
162	            states[index] = if states[index] == "elide" {
163	                "pass".to_string()
164	            } else {
165	                "elide".to_string()
166	            };
167	        }
168	    }
169	    zapcap_push_triage(&window)
170	}
171	
172	#[tauri::command]
173	fn copy_anonymized(window: tauri::WebviewWindow) -> Result<(), String> {
174	    let toggle_states = ZAPCAP_TOGGLE_STATES.lock()
175	        .map_err(|e| format!("lock error: {}", e))?
176	        .clone();
177	
178	    let anonymized = {
179	        let cache = ZAPCAP_LAST_CLINICAL.lock()
180	            .map_err(|e| format!("lock error: {}", e))?;
181	        let clinical = cache.as_ref()
182	            .ok_or_else(|| "no clinical data to anonymize".to_string())?;
183	        apcd::apcre_engine::apcre_anonymize(
184	            &clinical.plain_text,
185	            &clinical.findings,
186	            &toggle_states,
187	        )
188	    };
189	
190	    let mut clipboard = arboard::Clipboard::new()
191	        .map_err(|e| format!("clipboard error: {}", e))?;
192	    clipboard.set_text(anonymized)
193	        .map_err(|e| format!("clipboard error: {}", e))?;
194	
195	    zapcap_push_triage_with_feedback(&window, "Copied!")?;
196	
197	    let win = window.clone();
198	    std::thread::spawn(move || {
199	        std::thread::sleep(std::time::Duration::from_secs(2));
200	        let _ = zapcap_push_triage(&win);
201	    });
202	
203	    Ok(())
204	}
205	
206	// ---------------------------------------------------------------------------
207	// HTML push — render state and inject into webview
208	// ---------------------------------------------------------------------------
209	
210	fn zapcap_push_instruction(window: &tauri::WebviewWindow, diagnostic: &str) -> Result<(), String> {
211	    let html = zapcap_render_instruction(diagnostic);
