219	fn zapcap_push_triage_with_feedback(
220	    window: &tauri::WebviewWindow,
221	    btn_text: &str,
222	) -> Result<(), String> {
223	    // Clone data out of locks to avoid holding multiple locks simultaneously
224	    let (findings, plain_text) = {
225	        let cache = ZAPCAP_LAST_CLINICAL.lock()
226	            .map_err(|e| format!("lock error: {}", e))?;
227	        let clinical = cache.as_ref()
228	            .ok_or_else(|| "no clinical data for triage".to_string())?;
229	        (clinical.findings.clone(), clinical.plain_text.clone())
