263	fn zapcap_render_triage(
264	    findings: &[apcrm_Finding],
265	    plain_text: &str,
266	    toggle_states: &[String],
267	    btn_text: &str,
268	) -> String {
269	    let preview = zapcap_render_preview(findings, plain_text, toggle_states);
270	    let (yellow_html, red_html) = zapcap_render_findings(findings, toggle_states);
271	
272	    format!(
273	        "<h1>Ann&rsquo;s PHI Clipbuddy</h1>\
274	         <div id=\"document-preview\">{}</div>\
275	         <div id=\"findings-panel\">\
276	         <div class=\"findings-section\" id=\"findings-yellow\">\
277	         <h3>Questionable Findings</h3>\
278	         <div class=\"findings-list\" id=\"yellow-list\">{}</div></div>\
