292	fn zapcap_render_preview(
293	    findings: &[apcrm_Finding],
294	    plain_text: &str,
295	    toggle_states: &[String],
296	) -> String {
297	    // Build index-annotated list sorted by offset (byte offsets used directly)
298	    let mut sorted: Vec<(usize, &apcrm_Finding)> = findings.iter().enumerate().collect();
299	    sorted.sort_by(|a, b| a.1.offset.cmp(&b.1.offset).then(b.1.length.cmp(&a.1.length)));
300	
301	    let mut parts = Vec::new();
302	    let mut pos: usize = 0;
303	
304	    for (idx, f) in &sorted {
305	        if f.offset < pos { continue; } // skip overlap
306	
307	        // Text before this finding
308	        if f.offset > pos {
309	            parts.push(zapcap_escape_html(&plain_text[pos..f.offset]));
310	        }
311	
312	        // Finding span — byte offsets consumed directly, no conversion needed
313	        let end = f.offset + f.length;
314	        let cls = if toggle_states.get(*idx).map(|s| s.as_str()) == Some("pass") {
315	            "phi-pass"
316	        } else if f.severity == apcrm_Severity::Red {
317	            "phi-red"
318	        } else {
319	            "phi-yellow"
320	        };
321	
322	        parts.push(format!(
323	            "<span class=\"{}\" data-index=\"{}\">{}</span>",
324	            cls, idx, zapcap_escape_html(&plain_text[f.offset..end])
325	        ));
326	        pos = end;
327	    }
328	
329	    // Remaining text
330	    if pos < plain_text.len() {
331	        parts.push(zapcap_escape_html(&plain_text[pos..]));
332	    }
333	
334	    parts.join("")
335	}
