341	fn zapcap_render_findings(
342	    findings: &[apcrm_Finding],
343	    toggle_states: &[String],
344	) -> (String, String) {
345	    let mut yellow = Vec::new();
346	    let mut red = Vec::new();
347	
348	    for (i, f) in findings.iter().enumerate() {
349	        let state = toggle_states.get(i).map(|s| s.as_str()).unwrap_or("elide");
350	        let label = zapcap_format_category(f.category);
351	        let btn_text = if state == "elide" { "ELIDE \u{25bc}" } else { "PASS \u{25bc}" };
352	
353	        let entry = format!(
354	            "<div class=\"finding-entry\">\
355	             <span class=\"finding-text\">{}</span>\
356	             <span class=\"finding-category\">{}</span>\
357	             <button class=\"finding-toggle {}\" \
358	             onclick=\"window.__TAURI__.core.invoke('toggle_finding',{{index:{}}})\"\
359	             >{}</button></div>",
360	            zapcap_escape_html(&f.text),
361	            label,
362	            state,
363	            i,
364	            btn_text
365	        );
366	
367	        if f.severity == apcrm_Severity::Yellow {
368	            yellow.push(entry);
369	        } else {
370	            red.push(entry);
371	        }
372	    }
373	
374	    let yellow_html = if yellow.is_empty() {
375	        "<div class=\"empty-section\">None detected</div>".to_string()
376	    } else {
377	        yellow.join("")
378	    };
379	
380	    let red_html = if red.is_empty() {
381	        "<div class=\"empty-section\">None detected</div>".to_string()
382	    } else {
383	        red.join("")
384	    };
385	
386	    (yellow_html, red_html)
387	}
