393	fn zapcap_format_category(cat: apcrm_PhiCategory) -> &'static str {
394	    match cat {
395	        apcrm_PhiCategory::Name         => "NAME",
396	        apcrm_PhiCategory::Provider     => "PROVIDER",
397	        apcrm_PhiCategory::Facility     => "FACILITY",
398	        apcrm_PhiCategory::Date         => "DATE",
399	        apcrm_PhiCategory::Dob          => "DOB",
400	        apcrm_PhiCategory::Phone        => "PHONE",
401	        apcrm_PhiCategory::Email        => "EMAIL",
402	        apcrm_PhiCategory::Ssn          => "SSN",
403	        apcrm_PhiCategory::Mrn          => "MRN",
404	        apcrm_PhiCategory::Account      => "ACCOUNT",
405	        apcrm_PhiCategory::EncounterId  => "ENCOUNTER ID",
406	        apcrm_PhiCategory::Address      => "ADDRESS",
407	        apcrm_PhiCategory::HealthPlanId => "HEALTH PLAN ID",
408	        apcrm_PhiCategory::DeviceId     => "DEVICE ID",
409	        apcrm_PhiCategory::Npi          => "NPI",
410	        apcrm_PhiCategory::Dea          => "DEA",
411	        apcrm_PhiCategory::Url          => "URL",
412	        apcrm_PhiCategory::IpAddress    => "IP ADDRESS",
413	    }
414	}
415	
416	fn zapcap_escape_html(text: &str) -> String {
417	    text.replace('&', "&amp;")
418	        .replace('<', "&lt;")
419	        .replace('>', "&gt;")
420	        .replace('"', "&quot;")
421	}
422	
423	fn zapcap_js_string_literal(s: &str) -> String {
424	    let mut out = String::with_capacity(s.len() + 2);
425	    out.push('"');
426	    for c in s.chars() {
427	        match c {
428	            '\\'     => out.push_str("\\\\"),
429	            '"'      => out.push_str("\\\""),
430	            '\n'     => out.push_str("\\n"),
431	            '\r'     => out.push_str("\\r"),
432	            '\t'     => out.push_str("\\t"),
433	            '\u{08}' => out.push_str("\\b"),
434	            '\u{0C}' => out.push_str("\\f"),
435	            '\u{2028}' => out.push_str("\\u2028"),
436	            '\u{2029}' => out.push_str("\\u2029"),
437	            c if (c as u32) < 0x20 => out.push_str(&format!("\\u{:04x}", c as u32)),
438	            c => out.push(c),
439	        }
440	    }
441	    out.push('"');
442	    out
443	}
