459	            apcd::apcrl_error_now!(
460	                "create journal dir {}: {}", parent.display(), e
461	            );
462	            return;
463	        }
464	    }
465	    if let Err(e) = apcd::apcrl_log::apcrl_tee_init(&log_path) {
466	        apcd::apcrl_error_now!("log tee init failed: {}", e);
467	    }
468	}
