470	fn main() {
471	    zapcap_init_log_tee();
472	    apcd::apcrl_info_now!("starting Ann's PHI Clipbuddy");
473	    // Self-update watcher disabled for prototype — manual quit + relaunch
474	    // via /Users/Shared/apcua/Apcap.app is the current deploy workflow.
475	    // apcd::apcru_update::apcru_start_watcher();
476	    tauri::Builder::default()
477	        .invoke_handler(tauri::generate_handler![toggle_finding, copy_anonymized])
478	        .setup(|app| {
479	            use tauri::Manager;
480	            let window = app.get_webview_window("main")
481	                .expect("main window must exist");
482	            let win = window.clone();
483	            window.on_window_event(move |event| {
484	                if let tauri::WindowEvent::Focused(true) = event {
485	                    if let Err(e) = zapcap_handle_focus(&win) {
486	                        apcd::apcrl_error_now!("focus handler error: {}", e);
487	                    }
488	                }
489	            });
490	            Ok(())
491	        })
492	        .run(tauri::generate_context!())
493	        .unwrap_or_else(|e| apcd::apcrl_fatal_now!("tauri application error: {}", e));
494	}
